package circuitbreaker

import (
	"errors"
	"sync"
	"time"
)

type State int

const (
	Closed   State = iota // Normal operation
	Open                   // Rejecting requests
	HalfOpen               // Testing with single request
)

var ErrCircuitOpen = errors.New("circuit breaker is open")

type CircuitBreaker struct {
	mu            sync.Mutex
	state         State
	failures      int
	maxFailures   int
	resetTimeout  time.Duration
	lastFailure   time.Time
}

func New(maxFailures int, resetTimeout time.Duration) *CircuitBreaker {
	return &CircuitBreaker{
		state:        Closed,
		maxFailures:  maxFailures,
		resetTimeout: resetTimeout,
	}
}

func (cb *CircuitBreaker) State() State {
	cb.mu.Lock()
	defer cb.mu.Unlock()
	return cb.state
}

func (cb *CircuitBreaker) Execute(fn func() error) error {
	cb.mu.Lock()
	if cb.state == Open {
		if time.Since(cb.lastFailure) > cb.resetTimeout {
			cb.state = HalfOpen
		} else {
			cb.mu.Unlock()
			return ErrCircuitOpen
		}
	}
	cb.mu.Unlock()

	err := fn()

	cb.mu.Lock()
	defer cb.mu.Unlock()
	if err != nil {
		cb.failures++
		cb.lastFailure = time.Now()
		if cb.failures >= cb.maxFailures {
			cb.state = Open
		}
		return err
	}

	// Success
	cb.failures = 0
	cb.state = Closed
	return nil
}

package circuitbreaker

import (
	"errors"
	"testing"
	"time"
)

func TestClosedOnSuccess(t *testing.T) {
	cb := New(3, time.Second)
	err := cb.Execute(func() error { return nil })
	if err != nil {
		t.Fatal(err)
	}
	if cb.State() != Closed {
		t.Fatal("expected Closed")
	}
}

func TestOpensAfterMaxFailures(t *testing.T) {
	cb := New(2, time.Second)
	fail := errors.New("fail")
	cb.Execute(func() error { return fail })
	cb.Execute(func() error { return fail })
	if cb.State() != Open {
		t.Fatal("expected Open after 2 failures")
	}
	err := cb.Execute(func() error { return nil })
	if !errors.Is(err, ErrCircuitOpen) {
		t.Fatal("expected ErrCircuitOpen")
	}
}

func TestHalfOpenAfterTimeout(t *testing.T) {
	cb := New(1, 50*time.Millisecond)
	cb.Execute(func() error { return errors.New("fail") })
	if cb.State() != Open {
		t.Fatal("expected Open")
	}
	time.Sleep(60 * time.Millisecond)
	err := cb.Execute(func() error { return nil })
	if err != nil {
		t.Fatalf("expected success in half-open, got: %v", err)
	}
	if cb.State() != Closed {
		t.Fatal("expected Closed after successful half-open")
	}
}
